/**
 * Common, optional, input-related child nodes props to be bound in input elements and its siblings.
 * @public
 */
export interface SharedFormFieldProps {
    /** An id for the form control (also needed to link the label). */
    controlId?: string;
    /**
     * Defines if any form control within the FormField is required.
     * @defaultValue false
     */
    required?: boolean;
    /**
     * Defines if any form control within the FormField is disabled.
     * @defaultValue false
     */
    disabled?: boolean;
    /**
     * Defines if any form control within the FormField is aria-disabled.
     */
    ariaDisabled?: boolean;
    /**
     * Defines if any form control within the FormField is read-only.
     * @defaultValue false
     */
    readOnly?: boolean;
}
